import{_ as s,o as n,c as e,ak as l}from"./chunks/framework.DwHlt8HN.js";const h=JSON.parse('{"title":"MySQL 教程简介","description":"","frontmatter":{},"headers":[],"relativePath":"mysql/basic/overview.md","filePath":"mysql/basic/overview.md","lastUpdated":1774248380000}'),p={name:"mysql/basic/overview.md"};function i(r,a,t,d,c,b){return n(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="mysql-教程简介" tabindex="-1">MySQL 教程简介 <a class="header-anchor" href="#mysql-教程简介" aria-label="Permalink to “MySQL 教程简介”">​</a></h1><h2 id="这套教程适合谁" tabindex="-1">这套教程适合谁 <a class="header-anchor" href="#这套教程适合谁" aria-label="Permalink to “这套教程适合谁”">​</a></h2><p>写 Java 的同学大概率绕不开 MySQL。不管你是在校学生、刚入职的校招生，还是想系统梳理 MySQL 知识的老兵，这套教程都能用。</p><p>它不要求你有数据库基础——最好懂点 SQL 能跑查询就行。但它也不会只停留在「增删改查」层面：中高级部分会讲到索引原理、执行计划分析、事务隔离级别、主从复制……这些才是真正区分「会用 MySQL」和「懂 MySQL」的分水岭。</p><h2 id="教程结构" tabindex="-1">教程结构 <a class="header-anchor" href="#教程结构" aria-label="Permalink to “教程结构”">​</a></h2><p>整条学习路径分七个部分：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一部分：MySQL 基础入门</span></span>
<span class="line"><span>  ↓  安装配置 + 基本概念</span></span>
<span class="line"><span>第二部分：SQL 核心语法</span></span>
<span class="line"><span>  ↓  SELECT 查询 + 多表关联 + 函数 + 子查询</span></span>
<span class="line"><span>第三部分：数据库对象管理</span></span>
<span class="line"><span>  ↓  表结构设计 + 约束 + 视图 + 存储过程</span></span>
<span class="line"><span>第四部分：MySQL 高级特性</span></span>
<span class="line"><span>  ↓  逻辑架构 + 存储引擎 + 字符集 + 权限</span></span>
<span class="line"><span>第五部分：索引与性能优化</span></span>
<span class="line"><span>  ↓  索引原理 + 执行计划 + SQL 优化</span></span>
<span class="line"><span>第六部分：事务、锁与 MVCC</span></span>
<span class="line"><span>  ↓  ACID + 隔离级别 + 锁机制 + MVCC 原理</span></span>
<span class="line"><span>第七部分：日志、备份与主从复制</span></span>
<span class="line"><span>     主从搭建 + 备份恢复</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>每部分内部按「概念 → 语法 → 实战 → 注意事项」的顺序组织，循序渐进。</p><h2 id="学习目标" tabindex="-1">学习目标 <a class="header-anchor" href="#学习目标" aria-label="Permalink to “学习目标”">​</a></h2><p>学完这套教程，你应该能：</p><ul><li>独立完成 MySQL 安装、配置、远程连接</li><li>熟练编写复杂 SQL（多表查询、子查询、聚合统计）</li><li>理解 MySQL 逻辑架构和存储引擎差异，能选对引擎</li><li>掌握索引原理，能分析执行计划，能定位慢查询</li><li>理解事务和锁机制，能处理高并发下的数据一致性问题</li><li>搭建主从复制，设计备份策略</li></ul><h2 id="环境准备" tabindex="-1">环境准备 <a class="header-anchor" href="#环境准备" aria-label="Permalink to “环境准备”">​</a></h2><table tabindex="0"><thead><tr><th>软件</th><th>版本</th><th>说明</th></tr></thead><tbody><tr><td>MySQL</td><td>8.0+</td><td>主线版本，默认字符集 utf8mb4</td></tr><tr><td>MySQL</td><td>5.7</td><td>兼顾老项目，课程中会标注差异</td></tr><tr><td>客户端工具</td><td>Navicat / SQLyog / DBeaver</td><td>三选一，图形化操作更方便</td></tr></tbody></table><blockquote><p>MySQL 8.0 和 5.7 的核心差异会在对应章节说明，不用担心混用。</p></blockquote><h2 id="开始之前" tabindex="-1">开始之前 <a class="header-anchor" href="#开始之前" aria-label="Permalink to “开始之前”">​</a></h2><p>在开始之前，确保你已经：</p><ol><li>安装了 MySQL 8.0 或 5.7</li><li>能用 root 账号登录 MySQL</li><li>有一个趁手的客户端工具（不会用也行，命令行也能搞定一切）</li></ol><p>如果还没装好环境，先去看 <a href="/database/mysql/basic/install/8.0">MySQL 8.0 安装配置</a>，装好了再回来。</p><p>准备好了？从下一章开始，我们先搞清楚一个基本问题：<strong>为什么需要数据库？</strong></p>`,19)])])}const m=s(p,[["render",i]]);export{h as __pageData,m as default};
